import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Users, Shield, Trash2, UserCheck } from 'lucide-react';

const AdminDashboard = () => {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('ALL');

  useEffect(() => {
    fetchUsers();
  }, []);

  const fetchUsers = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get('http://localhost:8080/api/admin/users', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setUsers(response.data);
      setLoading(false);
    } catch (error) {
      console.error('Error fetching users:', error);
      setLoading(false);
    }
  };

  const handleUpdateRole = async (userId, newRole) => {
    try {
      const token = localStorage.getItem('token');
      await axios.patch(`http://localhost:8080/api/admin/users/${userId}/role`, { role: newRole }, {
        headers: { Authorization: `Bearer ${token}` }
      });
      alert('User role updated successfully!');
      fetchUsers();
    } catch (error) {
      console.error('Error updating role:', error);
      alert('Failed to update role.');
    }
  };

  const handleDeleteUser = async (userId) => {
    if (!window.confirm('Are you sure you want to delete this user?')) return;
    try {
      const token = localStorage.getItem('token');
      await axios.delete(`http://localhost:8080/api/admin/users/${userId}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      alert('User deleted successfully!');
      fetchUsers();
    } catch (error) {
      console.error('Error deleting user:', error);
      alert('Failed to delete user.');
    }
  };

  const filteredUsers = filter === 'ALL' 
    ? users 
    : users.filter(u => u.role === filter);

  if (loading) return <div className="container" style={{padding:'2rem'}}>Loading Admin Dashboard...</div>;

  return (
    <div className="container" style={{ padding: '2rem' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
        <h2 style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
          <Shield size={28} color="#d32f2f" /> System Administrator Panel
        </h2>
        <div className="form-group" style={{ flexDirection: 'row', gap: '10px', alignItems: 'center', marginBottom: 0 }}>
          <label>Filter by Role:</label>
          <select value={filter} onChange={(e) => setFilter(e.target.value)} style={{ padding: '8px', borderRadius: '4px' }}>
            <option value="ALL">All Users</option>
            <option value="CITIZEN">Citizens</option>
            <option value="AUTHORITY">Authorities</option>
            <option value="MODERATOR">Moderators</option>
            <option value="ADMINISTRATOR">Administrators</option>
          </select>
        </div>
      </div>

      <div className="dashboard-grid" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(400px, 1fr))', gap: '20px' }}>
        {filteredUsers.map(user => (
          <div key={user.id} className="report-card" style={{ 
            height: 'fit-content', 
            borderLeft: `5px solid ${user.role === 'ADMINISTRATOR' ? '#d32f2f' : user.role === 'AUTHORITY' ? '#ff9800' : '#2196f3'}` 
          }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
              <div>
                <h3 style={{ margin: '0 0 5px 0' }}>{user.name}</h3>
                <p style={{ margin: 0, color: '#666', fontSize: '0.9rem' }}>@{user.username} | {user.email}</p>
              </div>
              <span className="badge" style={{ 
                background: user.role === 'ADMINISTRATOR' ? '#ffebee' : user.role === 'AUTHORITY' ? '#fff3e0' : '#e3f2fd',
                color: user.role === 'ADMINISTRATOR' ? '#c62828' : user.role === 'AUTHORITY' ? '#e65100' : '#1565c0',
                fontWeight: 'bold'
              }}>
                {user.role}
              </span>
            </div>

            <div style={{ marginTop: '15px', fontSize: '0.85rem' }}>
              <p style={{ margin: '2px 0' }}><strong>Location:</strong> {user.village}, {user.district}, {user.state}</p>
              <p style={{ margin: '2px 0' }}><strong>Mobile:</strong> {user.mobile}</p>
              {user.role === 'CITIZEN' && <p style={{ margin: '2px 0' }}><strong>Credibility Score:</strong> {user.credibilityScore}</p>}
              {user.role === 'AUTHORITY' && (
                <>
                  <p style={{ margin: '2px 0' }}><strong>Department:</strong> {user.department || 'N/A'}</p>
                  <p style={{ margin: '2px 0' }}><strong>Designation:</strong> {user.designation || 'N/A'}</p>
                </>
              )}
            </div>

            <hr style={{ margin: '15px 0' }} />

            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
                <label style={{ fontSize: '0.8rem' }}>Change Role:</label>
                <select 
                  value={user.role}
                  onChange={(e) => handleUpdateRole(user.id, e.target.value)}
                  style={{ padding: '5px', fontSize: '0.8rem' }}
                >
                  <option value="CITIZEN">Citizen</option>
                  <option value="AUTHORITY">Authority</option>
                  <option value="MODERATOR">Moderator</option>
                  <option value="ADMINISTRATOR">Administrator</option>
                </select>
              </div>
              <button 
                onClick={() => handleDeleteUser(user.id)}
                style={{ 
                  background: 'none', 
                  border: 'none', 
                  color: '#d32f2f', 
                  cursor: 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '4px',
                  fontSize: '0.8rem'
                }}
              >
                <Trash2 size={16} /> Delete
              </button>
            </div>
          </div>
        ))}
      </div>

      {filteredUsers.length === 0 && (
        <div style={{ textAlign: 'center', padding: '3rem', background: '#f5f5f5', borderRadius: '8px' }}>
          <Users size={48} color="#ccc" style={{ marginBottom: '10px' }} />
          <p>No users found for the selected role.</p>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;
